// TG-143: Fetch yesterday's completed jobs from Supabase
const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

// Look back 24 hours for completed jobs
const now = new Date();
const twentyFourHoursAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000).toISOString();

let completions = [];
try {
  completions = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/jobber_email_events?event_type=eq.job_completed&created_at=gte.${twentyFourHoursAgo}&select=customer_name,customer_address,service_type,created_at`,
    headers: supabaseHeaders
  });
} catch (e) {
  completions = [];
}

if (!Array.isArray(completions) || completions.length === 0) {
  return [{ json: { completions: [], _skip: true, message: 'No completed jobs in last 24h' } }];
}

return [{ json: { completions, jobCount: completions.length } }];

// TG-143: Extract zip codes from completed job addresses
const data = $input.first().json;
if (data._skip) return [{ json: data }];

const completions = data.completions || [];
const zipPattern = /\b(\d{5})(-\d{4})?\b/;
const jobsByZip = {};

// Madison area zip codes for validation
const madisonAreaZips = new Set([
  '53703', '53704', '53705', '53706', '53711', '53713', '53714',
  '53716', '53717', '53718', '53719', '53726',
  '53562', '53597', '53590', '53593', '53558'
]);

for (const job of completions) {
  const addr = job.customer_address || '';
  const match = addr.match(zipPattern);
  if (match) {
    const zip = match[1];
    // Only process Madison area zips
    if (!madisonAreaZips.has(zip)) continue;
    if (!jobsByZip[zip]) jobsByZip[zip] = [];
    jobsByZip[zip].push({
      customerName: job.customer_name,
      address: addr,
      serviceType: job.service_type || 'lawn care'
    });
  }
}

const zipCodes = Object.keys(jobsByZip);
if (zipCodes.length === 0) {
  return [{ json: { _skip: true, message: 'No valid Madison-area zip codes found in completed jobs' } }];
}

return [{ json: { jobsByZip, zipCodes, jobCount: data.jobCount } }];

// TG-143: Find neighbor leads in same zip codes, dedup 30-day window
const data = $input.first().json;
if (data._skip) return [{ json: data }];

const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
const neighborLeads = [];

for (const zip of data.zipCodes) {
  const serviceType = data.jobsByZip[zip][0].serviceType;

  try {
    // Find leads in this zip code that are not converted customers
    const leads = await this.helpers.httpRequest({
      method: 'GET',
      url: `${supabaseUrl}/leads?address=like.*${zip}*&lead_tier=neq.converted&select=id,name,phone,address`,
      headers: supabaseHeaders
    });

    if (!Array.isArray(leads)) continue;

    // Check neighbor_outreach table for 30-day dedup
    let recentOutreach = [];
    try {
      recentOutreach = await this.helpers.httpRequest({
        method: 'GET',
        url: `${supabaseUrl}/neighbor_outreach?sent_at=gte.${thirtyDaysAgo}&zip_code=eq.${zip}&select=lead_phone`,
        headers: supabaseHeaders
      });
    } catch (e) {
      recentOutreach = [];
    }
    const recentPhones = new Set((recentOutreach || []).map(r => r.lead_phone));

    for (const lead of leads) {
      if (!lead.phone) continue;
      // Skip if already contacted in last 30 days
      if (recentPhones.has(lead.phone)) continue;

      neighborLeads.push({
        leadId: lead.id,
        name: lead.name || 'Neighbor',
        phone: lead.phone,
        zip,
        serviceType
      });
    }
  } catch (e) { /* continue to next zip */ }
}

if (neighborLeads.length === 0) {
  return [{ json: { _skip: true, message: 'No eligible neighbor leads found', zipCodes: data.zipCodes, jobCount: data.jobCount } }];
}

return [{ json: { neighborLeads, zipCodes: data.zipCodes, jobCount: data.jobCount, leadCount: neighborLeads.length } }];

// TG-143: Build neighbor outreach SMS messages with rotation
const data = $input.first().json;
if (data._skip) return [{ json: data }];

const templates = [
  (first, svc) => `Hi ${first}! TotalGuard Yard Care was just working in your neighborhood today on a ${svc} job. Your neighbors trust us with their lawn \u2014 we'd love to help you too! Free quote: tgyardcare.com or call (608) 535-6057. Reply STOP to opt out.`,
  (first, svc) => `Hi ${first}! We just finished a ${svc} job near you. While we're in the neighborhood, we'd be happy to give you a free estimate! tgyardcare.com | (608) 535-6057. Reply STOP to opt out.`
];

const messages = [];

for (let i = 0; i < data.neighborLeads.length; i++) {
  const lead = data.neighborLeads[i];
  const firstName = lead.name.split(' ')[0];
  const template = templates[i % templates.length];
  const messageBody = template(firstName, lead.serviceType);

  messages.push({
    json: {
      to_phone: lead.phone,
      message_body: messageBody,
      workflow_name: 'TG-143-neighbor-outreach',
      message_type: 'neighbor_marketing',
      _lead_name: lead.name,
      _lead_phone: lead.phone,
      _zip: lead.zip,
      _service: lead.serviceType
    }
  });
}

return messages;

// TG-143: Log each outreach to neighbor_outreach table
const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

const items = $input.all();
const logged = [];

for (const item of items) {
  const d = item.json;
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${supabaseUrl}/neighbor_outreach`,
      headers: supabaseHeaders,
      body: {
        lead_phone: d._lead_phone || d.to_phone,
        lead_name: d._lead_name || '',
        zip_code: d._zip || '',
        job_service_type: d._service || '',
        sent_at: new Date().toISOString()
      }
    });
    logged.push({ name: d._lead_name, zip: d._zip });
  } catch (e) {
    logged.push({ name: d._lead_name, zip: d._zip, error: e.message });
  }
}

return [{ json: { logged, loggedCount: logged.length } }];

